typedef int cap_handle_t;
void cap06_close(cap_handle_t handle);
cap_handle_t cap06_open(void);
int cap06_is_valid(cap_handle_t handle);

void cap06_mixed_weak_move_hazard(id owner) {
    cap_handle_t fd __attribute__((objc_resource(close=cap06_close, invalid=-1))) = cap06_open();
    void (^handler)(void) = [weak owner, move fd] {
        if (owner) {
            (void)fd;
        }
    };
    if (owner) {
        cap06_is_valid(fd);
    }
    handler();
}
